ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/entertainment#>
PREFIX p: <http://ambrosia.example.org/entertainment/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
CHOICE attachment {
  high: { SELECT DISTINCT ?o0 WHERE {
  {
    ?gallery a :Gallery .
    ?photography a :Photography .
    ?photography p:hasGallery ?gallery .
    ?photography p:Title ?title .
    ?gallery p:name ?name_f .
    FILTER(STR(?name_f) = "MoMA - Museum of Modern Art")
    BIND(?title AS ?o0)
  }
  UNION
  {
    ?gallery a :Gallery .
    ?painting a :Painting .
    ?painting p:hasGallery ?gallery .
    ?painting p:Title ?title .
    ?gallery p:name ?name_f .
    FILTER(STR(?name_f) = "MoMA - Museum of Modern Art")
    BIND(?title AS ?o0)
  }
} }
  low: { SELECT DISTINCT ?o0 WHERE {
  {
    ?gallery a :Gallery .
    ?photography a :Photography .
    ?photography p:hasGallery ?gallery .
    ?photography p:Title ?title .
    BIND(?title AS ?o0)
  }
  UNION
  {
    ?gallery a :Gallery .
    ?painting a :Painting .
    ?painting p:hasGallery ?gallery .
    ?painting p:Title ?title .
    ?gallery p:name ?name_f .
    FILTER(STR(?name_f) = "MoMA - Museum of Modern Art")
    BIND(?title AS ?o0)
  }
} }
}
